--
-- Table structure for table `t044t_country_currencies`
--

DROP TABLE IF EXISTS `t044t_country_currencies`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `t044t_country_currencies` (
  `id` int NOT NULL AUTO_INCREMENT COMMENT 'Consecutivo Гәnico del registro',
  `id_country` int NOT NULL COMMENT 'Referencia al id del paГӯs',
  `id_currency` int NOT NULL COMMENT 'Referencia al id de la moneda',
  `is_primary` int NOT NULL DEFAULT '1' COMMENT 'Indicador de moneda principal: 1 principal, 0 secundaria. Ej: PanamГЎ tiene PAB(1) y USD(0)',
  `status` int NOT NULL DEFAULT '1' COMMENT 'Estado del registro: 1 activo, 0 inactivo',
  `created_at` datetime(6) NOT NULL COMMENT 'Fecha y hora de creaciГіn del registro',
  `updated_at` datetime(6) NOT NULL COMMENT 'Fecha y hora de Гәltima actualizaciГіn del registro',
  `created_by` int NOT NULL COMMENT 'Usuario que creГі el registro',
  `updated_by` int NOT NULL COMMENT 'Usuario que realizГі la Гәltima actualizaciГіn del registro',
  PRIMARY KEY (`id`),
  UNIQUE KEY `UK_t044t_id_country_id_currency` (`id_country`,`id_currency`),
  KEY `IDX_t044t_id_country` (`id_country`),
  KEY `IDX_t044t_id_currency` (`id_currency`),
  CONSTRAINT `FK_t044t_id_country_t074t` FOREIGN KEY (`id_country`) REFERENCES `t074t_countries` (`id`),
  CONSTRAINT `FK_t044t_id_currency_t041t` FOREIGN KEY (`id_currency`) REFERENCES `t041t_currencies` (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=257 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='RelaciГіn paГӯses-monedas. Soporta paГӯses con mГәltiples monedas';
/*!40101 SET character_set_client = @saved_cs_client */;

