--
-- Table structure for table `t076t_states`
--

DROP TABLE IF EXISTS `t076t_states`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `t076t_states` (
  `id` int NOT NULL AUTO_INCREMENT COMMENT 'Consecutivo Гәnico del registro',
  `geo_id` int NOT NULL COMMENT 'ID del departamento en geonames.org',
  `id_country` int NOT NULL COMMENT 'Identificador del paГӯs',
  `code` varchar(16) NOT NULL COMMENT 'CГіdigo interno del departamento',
  `code_dane` varchar(16) DEFAULT NULL COMMENT 'CГіdigo DANE del departamento',
  `code_dian` varchar(16) DEFAULT NULL COMMENT 'CГіdigo DIAN del departamento',
  `code_iso_numeric` varchar(16) NOT NULL COMMENT 'CГіdigo ISO numГ©rico del departamento',
  `code_iso_alpha2` varchar(16) NOT NULL COMMENT 'CГіdigo ISO alpha-2 del departamento',
  `code_iso_alpha3` varchar(16) NOT NULL COMMENT 'CГіdigo ISO alpha-3 del departamento',
  `phone_code` varchar(16) NOT NULL COMMENT 'Indicativo telefГіnico del departamento',
  `id_division_type` int NOT NULL COMMENT 'Identificador del tipo de divisiГіn geogrГЎfica',
  `name_spanish` varchar(128) NOT NULL COMMENT 'Nombre del departamento en espaГұol',
  `name_english` varchar(128) NOT NULL COMMENT 'Nombre del departamento en inglГ©s',
  `name_iso` varchar(128) NOT NULL COMMENT 'Nombre oficial ISO del departamento',
  `name_original` varchar(128) NOT NULL COMMENT 'Nombre del departamento en idioma oficial',
  `name_transcribed` varchar(128) NOT NULL COMMENT 'Nombre del departamento transcrito a alfabeto latino legible',
  `status` int NOT NULL DEFAULT '1' COMMENT 'Estado del registro: 1=activo, 0=inactivo',
  `created_at` datetime(6) NOT NULL COMMENT 'Fecha y hora de creaciГіn del registro',
  `updated_at` datetime(6) NOT NULL COMMENT 'Fecha y hora de Гәltima actualizaciГіn del registro',
  `created_by` int NOT NULL COMMENT 'Usuario que creГі el registro',
  `updated_by` int NOT NULL COMMENT 'Usuario que realizГі la Гәltima actualizaciГіn del registro',
  PRIMARY KEY (`id`),
  UNIQUE KEY `UK_t076t_geo_id` (`geo_id`),
  KEY `IDX_t076t_name_spanish` (`name_spanish`),
  KEY `IDX_t076t_name_english` (`name_english`),
  KEY `IDX_t076t_id_country` (`id_country`),
  KEY `IDX_t076t_code` (`code`),
