CREATE TABLE `t078t_municipalities` (
  `id` int NOT NULL AUTO_INCREMENT COMMENT 'Consecutivo Гәnico del registro',
  `geo_id` int NOT NULL COMMENT 'ID del municipio en geonames.org',
  `id_country` int NOT NULL COMMENT 'Identificador del paГӯs',
  `id_state` int NOT NULL COMMENT 'Identificador del departamento',
  `code` varchar(16) NOT NULL COMMENT 'CГіdigo interno del municipio',
  `code_dane` varchar(16) DEFAULT NULL COMMENT 'CГіdigo DANE del municipio',
  `code_dian` varchar(16) DEFAULT NULL COMMENT 'CГіdigo DIAN del municipio',
  `code_iso_numeric` varchar(16) NOT NULL COMMENT 'CГіdigo ISO numГ©rico del municipio',
  `code_iso_alpha2` varchar(16) NOT NULL COMMENT 'CГіdigo ISO alpha-2 del municipio',
  `code_iso_alpha3` varchar(16) NOT NULL COMMENT 'CГіdigo ISO alpha-3 del municipio',
  `phone_code` varchar(16) NOT NULL COMMENT 'Indicativo telefГіnico del municipio',
  `id_division_type` int NOT NULL COMMENT 'Identificador del tipo de divisiГіn geogrГЎfica',
  `name_spanish` varchar(128) NOT NULL COMMENT 'Nombre del municipio en espaГұol',
  `name_english` varchar(128) NOT NULL COMMENT 'Nombre del municipio en inglГ©s',
  `name_iso` varchar(128) NOT NULL COMMENT 'Nombre oficial ISO del municipio',
  `name_original` varchar(128) NOT NULL COMMENT 'Nombre del municipio en idioma oficial',
  `name_transcribed` varchar(128) NOT NULL COMMENT 'Nombre del municipio transcrito a alfabeto latino legible',
  `latitude` decimal(10,7) NOT NULL COMMENT 'Latitud geogrГЎfica del centroide del municipio',
  `longitude` decimal(10,7) NOT NULL COMMENT 'Longitud geogrГЎfica del centroide del municipio',
  `status` int NOT NULL DEFAULT '1' COMMENT 'Estado del registro: 1=activo, 0=inactivo',
  `created_at` datetime(6) NOT NULL COMMENT 'Fecha y hora de creaciГіn del registro',
  `updated_at` datetime(6) NOT NULL COMMENT 'Fecha y hora de Гәltima actualizaciГіn del registro',
  `created_by` int NOT NULL COMMENT 'Usuario que creГі el registro',
  `updated_by` int NOT NULL COMMENT 'Usuario que realizГі la Гәltima actualizaciГіn del registro',
  PRIMARY KEY (`id`),
  UNIQUE KEY `UK_t078t_geo_id` (`geo_id`),
  KEY `IDX_t078t_name_spanish` (`name_spanish`),
  KEY `IDX_t078t_name_english` (`name_english`),
