  KEY `IDX_t078t_code_dane` (`code_dane`),
  KEY `IDX_t078t_id_division_type` (`id_division_type`),
  KEY `IDX_t078t_id_country_state_name` (`id_country`,`id_state`,`name_spanish`),
  CONSTRAINT `FK_t078t_id_country_t074t` FOREIGN KEY (`id_country`) REFERENCES `t074t_countries` (`id`),
  CONSTRAINT `FK_t078t_id_division_type_t070t` FOREIGN KEY (`id_division_type`) REFERENCES `t070t_division_type` (`id`),
  CONSTRAINT `FK_t078t_id_state_t076t` FOREIGN KEY (`id_state`) REFERENCES `t076t_states` (`id`),
  CONSTRAINT `CHK_NE_t078t_code` CHECK ((`code` <> _utf8mb4'')),
  CONSTRAINT `CHK_NE_t078t_name_english` CHECK ((`name_english` <> _utf8mb4'')),
